const output = [];

for (const item of $input.all()) {
  const files = item.json.audio || [];
  const binaries = item.binary || {};

  const binaryEntries = Object.entries(binaries);

  for (let i = 0; i < files.length; i++) {
    const file = files[i];

    // Tenta encontrar o binário pelo padrão comum do n8n: audio_0, audio_1...
    let binaryKey = `audio_${i}`;

    // Se não existir, tenta encontrar pelo nome do arquivo
    if (!binaries[binaryKey]) {
      const found = binaryEntries.find(([key, binary]) => {
        const binaryFileName =
          binary.fileName ||
          binary.filename ||
          binary.file_name ||
          '';

        return binaryFileName === file.filename;
      });

      if (found) {
        binaryKey = found[0];
      }
    }

    // Se ainda não achar, pega pela posição
    if (!binaries[binaryKey] && binaryEntries[i]) {
      binaryKey = binaryEntries[i][0];
    }

    if (!binaries[binaryKey]) {
      throw new Error(`Binário não encontrado para o arquivo: ${file.filename}`);
    }

    output.push({
      json: {
        submittedAt: item.json.submittedAt,
        formMode: item.json.formMode,

        file_index: i,
        file_name: file.filename,
        mime_type: file.mimetype,
        size: file.size,

        original_binary_key: binaryKey,
        binary_field: 'data',
      },
      binary: {
        data: binaries[binaryKey],
      },
    });
  }
}

return output;

